import anthropic

client = anthropic.Anthropic()

ORCHESTRATOR_MODEL = "claude-opus-4-8"
WORKER_MODEL = "claude-sonnet-4-6"
CLASSIFIER_MODEL = "claude-haiku-4-5-20251001"


def orchestrate(task: str, tools: list[dict]) -> str:
    """
    Two-tier agent: Opus orchestrates, Sonnet workers execute.
    The orchestrator decomposes the task and decides when it is done.
    Workers carry out individual tool-use steps.
    """
    # Step 1 — orchestrator plans
    plan_response = client.messages.create(
        model=ORCHESTRATOR_MODEL,
        max_tokens=1024,
        messages=[{
            "role": "user",
            "content": (
                f"Break this task into at most 5 concrete subtasks. "
                f"Return a JSON list of subtask descriptions.\n\nTask: {task}"
            ),
        }],
    )
    import json
    plan_text = plan_response.content[0].text
    try:
        subtasks = json.loads(plan_text)
    except json.JSONDecodeError:
        subtasks = [task]  # fall back to single task

    # Step 2 — workers execute each subtask
    results = []
    for subtask in subtasks:
        messages = [{"role": "user", "content": subtask}]
        while True:
            resp = client.messages.create(
                model=WORKER_MODEL,
                max_tokens=4096,
                tools=tools,
                messages=messages,
            )
            messages.append({"role": "assistant", "content": resp.content})
            if resp.stop_reason == "end_turn":
                for block in resp.content:
                    if hasattr(block, "text"):
                        results.append(block.text)
                break
            tool_results = []
            for block in resp.content:
                if block.type == "tool_use":
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": f"result of {block.name}",
                    })
            messages.append({"role": "user", "content": tool_results})

    # Step 3 — orchestrator synthesises
    synthesis_response = client.messages.create(
        model=ORCHESTRATOR_MODEL,
        max_tokens=2048,
        messages=[{
            "role": "user",
            "content": (
                f"Synthesise these subtask results into a final answer for: {task}\n\n"
                + "\n\n".join(f"Subtask result:\n{r}" for r in results)
            ),
        }],
    )
    return synthesis_response.content[0].text

from dataclasses import dataclass


@dataclass
class ModelBudget:
    """
    Track per-model token usage across an agent run to monitor cost
    and stay within a token budget.
    """
    usage: dict[str, dict[str, int]]  # model -> {input, output}

    @classmethod
    def empty(cls) -> "ModelBudget":
        return cls(usage={})

    def record(self, model: str, input_tokens: int, output_tokens: int) -> None:
        if model not in self.usage:
            self.usage[model] = {"input": 0, "output": 0}
        self.usage[model]["input"] += input_tokens
        self.usage[model]["output"] += output_tokens

    def total_tokens(self) -> int:
        return sum(
            v["input"] + v["output"]
            for v in self.usage.values()
        )

    def summary(self) -> str:
        lines = [f"Total tokens: {self.total_tokens():,}"]
        for model, counts in sorted(self.usage.items()):
            lines.append(
                f"  {model}: {counts['input']:,} in + {counts['output']:,} out"
            )
        return "\n".join(lines)


