import anthropic
import time


def run_with_model_fallback(
    messages: list[dict],
    preferred_model: str = "claude-sonnet-4-6",
    fallback_model: str = "claude-haiku-4-5-20251001",
    max_tokens: int = 4096,
) -> anthropic.types.Message:
    """
    Try the preferred model; fall back to a cheaper model on rate-limit errors.
    Useful in high-throughput pipelines where Sonnet quota may be exhausted.
    """
    client = anthropic.Anthropic()
    models_to_try = [preferred_model, fallback_model]

    for i, model in enumerate(models_to_try):
        try:
            return client.messages.create(
                model=model,
                max_tokens=max_tokens,
                messages=messages,
            )
        except anthropic.RateLimitError:
            if i < len(models_to_try) - 1:
                time.sleep(2 ** i)  # brief backoff before fallback
                continue
            raise
        except anthropic.APIStatusError as e:
            if e.status_code >= 500 and i < len(models_to_try) - 1:
                time.sleep(2 ** i)
                continue
            raise

    raise RuntimeError("All models exhausted")  # unreachable
